def change_project_config(uid: str, role: str, proj: str, settings_update: dict):
    # Check if project exists
    if proj not in PROJECTS_DB:
        raise PermissionError(f"Project {proj} does not exist")

    project = PROJECTS_DB[proj]

    # Check if user is a member of the project
    if uid not in project['members']:
        raise PermissionError(f"User {uid} is not a member of project {proj}")

    # Check if user is the creator
    is_creator = uid == project['creator_id']

    # Define roles that can update settings (must be a member AND have proper role)
    allowed_roles = {'project_manager', 'team_lead', 'admin'}

    # Allow access if user is creator OR has an allowed role
    if not (is_creator or role in allowed_roles):
        raise PermissionError(f"User {uid} with role '{role}' is not authorized to update project settings")

    # Update the settings
    for key, value in settings_update.items():
        project['settings'][key] = value

    # Return success message
    return {
        'status': 'success',
        'message': f'Project {proj} settings updated successfully',
        'updated_settings': project['settings']
    }


